# file_a.py
from typing import Optional, Dict, Any

class UserRepository:
    def __init__(self, db_path: str = "/var/db/users.txt"):
        self.db_path = db_path

    def fetch_by_id(self, user_id: int) -> Optional[Dict[str, Any]]:
        try:
            with open(self.db_path) as db:
                for line in db:
                    uid, name = line.strip().split(",")
                    if uid == str(user_id):
                        return {"id": uid, "name": name}
        except (FileNotFoundError, ValueError):
            pass
        return None

def fetch_user(user_id: int) -> Optional[Dict[str, Any]]:
    repo = UserRepository()
    return repo.fetch_by_id(user_id)
